var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"나는 꿈에서 본 별똥별을 쫓다가 그곳에 다다랐다.","JPN":"僕は夢で見た流れ星を追いかけて、そこに辿り着いた。","ENG":"In my dream, I chased a shooting star, and reached a certain place.","TWN":"我在夢裡追著流星，追著追著便來到那裡。"},"stage":{"bg":"NANAHARA_03","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"잔잔한 바람에 벚꽃이 휘날리던.","JPN":"穏やかな風に桜が舞い散った。","ENG":"Cherry blossoms fluttered in the gentle wind.","TWN":"一個櫻花在微風中飄揚。"},"stage":{"bg":"NANAHARA_03","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"벚나무의 향기가 가득한 장소.","JPN":"桜の匂いに満ちた場所。","ENG":"The air was so fragrant.","TWN":"充滿櫻花香氣的地方。"},"stage":{"bg":"NANAHARA_03","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"그날 만난 소녀는… 나와 다른 세상에 있는 사람 같았다.","JPN":"あの日出会った少女は……\\n僕とは異なる世界を生きる人のようだった。","ENG":"The girl I met that day... She looked as if she was from another world.","TWN":"那天見到的少女… 感覺和我是不同世界的人。"},"stage":{"bg":"NANAHARA_03","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"마치 꿈을 꾸고 있는 것처럼.","JPN":"まるで夢を見ているかのように。","ENG":"Like a dream...","TWN":"就像在做夢一樣。"},"stage":{"bg":"NANAHARA_03","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"우리는 각자 다른 곳을 바라보고 있었다.","JPN":"僕たちはそれぞれ違う場所を見つめていた。","ENG":"We were looking at different places.","TWN":"我們各自看著不同的地方。"},"stage":{"bg":"NANAHARA_03","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"너는……?","JPN":"君は……？","ENG":"You are...","TWN":"你是……？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"침식체에게 입은 상처군요.","JPN":"侵食体による傷ですね。","ENG":"This is a wound from a C.O.","TWN":"這是侵蝕體造成的傷口。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"상처는 깊지 않지만, <color=#ffd34c>독</color>은 이미 혈관을 타고 스며들었습니다.","JPN":"傷は深くありませんが、<color=#ffd34c>毒</color>がすでに血管から浸透しています。","ENG":"It’s not deep, but the <color=#ffd34c>poison</color> is already flowing in her veins.","TWN":"傷口不深，但<color=#ffd34c>毒</color>已經藉由血管滲入。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"이로하의 상처가…… 아물고 있어.","JPN":"いろはの傷が……治っている。","ENG":"The cut... It’s closing.","TWN":"伊呂波的傷口…… 正在癒合。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"치유 능력을 가진 카운터였구나. 다행이다.","JPN":"治癒能力のカウンターだったんだね。よかった。","ENG":"You’re a Counter with healing power. Thank you.","TWN":"原來是有治癒能力的制裁者，真是太好了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"안심하기엔 아직 일러요. 독이 퍼지지 않게 조치했지만 이것만으론 부족합니다.","JPN":"安心するにはまだ早いです。\\n毒が広がらないように処置しましたが、これだけでは足りません。","ENG":"Don’t thank me yet. I only stopped the poison from spreading, but this is not enough.","TWN":"還不能放心。雖然有先做一些處理防止毒性擴散，但光這樣是不夠的。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"독기의 원흉이 건재한 이상, 이미 혈관에 퍼진 독을 정화할 방법은 없으니까요.","JPN":"毒の元凶が健在である以上、\\nすでに血管に広がった毒を浄化する方法はありませんから。","ENG":"As long as the source of the poison is still out there, you can’t remove what’s already inside her body.","TWN":"只要毒根還在，就沒有辦法淨化已經擴散到血管的毒。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"독이라고? 1종 침식체한테 그런 게 있었어?","JPN":"毒？　第1種侵食体にそんな能力があるのか？","ENG":"Poison? I didn’t know Category 1 C.O.s were poisonous.","TWN":"毒？1類侵蝕體有毒嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네. 본래는 없습니다. 그 때문에 그대를 찾아온 것이죠.","JPN":"はい、本来はございません。ですので、貴方を訪ねて来たのです。","ENG":"Normally they aren’t. That’s why I came here to see you.","TWN":"對，本來是沒有的，所以才會來找你。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"나를……?","JPN":"僕を……？","ENG":"See me?","TWN":"找我……？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"인사가 늦었군요. 나나하라 가문의 당주, 나나하라 치나츠라고 합니다.","JPN":"ご挨拶が遅れました。七原家の当主、七原千夏と申します。","ENG":"Let me introduce myself. I’m Nanahara Chinatsu, the leader of the Nanahara family.","TWN":"還沒介紹，我是七原家族的堂主七原千夏。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그간 무탈히 지내셨나요, 미나토 님.","JPN":"お変わりございませんでしたか、湊様。","ENG":"How have you been, Mr. Nayuka.","TWN":"別來無恙，南裕夏。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"응? 혹시 날 알고 있어?","JPN":"うん？　もしかして僕のことを知ってる？","ENG":"Huh? You know me?","TWN":"嗯？你認識我嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그러고 보니 낯이 익긴 한데……. 아르바이트하는 가게에서 봤나…….","JPN":"そういえばどこかで見たような気が……バイト先で会ったかな……","ENG":"You do look familiar... Maybe I met you at the shop that I work at?","TWN":"這麼說來，好像是有點面熟……是在打工的店裡見過嗎……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……그래요. 잊고 계셨군요.","JPN":"……そうですか。忘れていらっしゃるのですね。","ENG":"... I see. You don’t remember me.","TWN":"……你不記得嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"괜찮습니다. 저희의 인연은 유년 시절의 짧고 사소한 기억이니.","JPN":"大丈夫です。私たちの縁は、幼い頃の短くて些細な記憶ですので。","ENG":"It’s alright. We only met briefly in our childhood.","TWN":"沒關係，畢竟我們的緣分只是孩童時期短暫又不重要的回憶。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아하하…… 그렇게 들으니 왠지 미안해지네.","JPN":"あはは……そう言われると何だか申し訳ないな。","ENG":"Hah hah... I’m sorry that I don’t remember you.","TWN":"呵呵呵…… 這樣講有點不好意思呢。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"미나토 님.","JPN":"湊様。","ENG":"Mr. Nayuka.","TWN":"南裕夏。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Yes?","TWN":"嗯？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"제가 그대를 찾아온 것은 명분이 있기 때문입니다.","JPN":"私が貴方を訪ねたのは大義名分があるためです。","ENG":"I’m here to see you for a reason.","TWN":"我來找你是有原因的。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저희 나나하라 가문연합은, 오래 전부터 거대한 위협과 싸워 왔어요.","JPN":"私たち七原家連合は、遥か昔から巨大な脅威と戦ってまいりました。","ENG":"We, the Nanahara Family Alliance, have been fighting the great threat for a very long time.","TWN":"我們七原家族聯盟從很久以前就在對抗巨大的威脅。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하지만 위협이 사라지자 연합의 결속은 약해졌고, 많은 가문들이 대오를 이탈했죠.","JPN":"しかし脅威が消えると連合の結束は弱まり、\\n多くの家門が連合から離脱していきました。","ENG":"When the threat disappeared, the bonds of our Alliance began to slip, and many families left us.","TWN":"但是，威脅消失後，聯盟的團結力減弱，很多家族開始出走。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"인간의 삶은 평화를 누리며 살아가기에도 짧습니다. 그렇기에 연합도 그들에게 투쟁을 강요하지 않았어요.","JPN":"人の人生というものは、平和を享受しながら生きていくには\\nあまりに短いものです。そのため、連合も彼らに闘争を強いていませんでした。","ENG":"Our life is short as is, so the Alliance didn’t force those families to come back and continue the struggle.","TWN":"人生那麼短暫，因此家族也沒有強迫他們起來對抗。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하지만 <color=#ffd34c>그것</color>이 다시 세상으로 나오려는 지금……","JPN":"ですが、<color=#ffd34c>あれ</color>が再びこの世に解き放たれようとしている今……","ENG":"But <color=#ffd34c>it</color> is coming back now...","TWN":"但是<color=#ffd34c>那個</color>似乎又再次出現……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"안타깝게도 남은 연합원들의 힘만으로는 감당하기 어렵게 되었습니다.","JPN":"残念ながら、残った連合員の力だけでは到底及ばないでしょう。","ENG":"And the current Alliance cannot fight the threat just by ourselves.","TWN":"遺憾的是，單憑剩下的聯盟成員是無法與其抗衡的。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그대의 도움이 필요합니다. 나유카 미나토.","JPN":"貴方の力が必要です、奈由香湊。","ENG":"We need your help, Nayuka Minato.","TWN":"因此我需要你的幫助，南裕夏。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"자, 잠깐만. 만화에서 자주 보던 전개 같긴 한데, 정리가 안 돼서 말이야.","JPN":"ま、待ってよ。漫画でよく見る展開だけど、\\nちょっと整理が追いつかないんだ。","ENG":"W-wait. I think I saw something like this in a comic book, but I need some time to think...","TWN":"等…等等。這好像是在漫畫裡才會有的情節一樣，我需要消化一下。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"만화? 그게 뭐죠?","JPN":"漫画？　それは何でしょうか？","ENG":"A comic book? What is that?","TWN":"漫畫？那是什麼？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아니, 그러니까…….","JPN":"いや、だから……","ENG":"Um, I don’t know what to say...","TWN":"你的意思是說……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아무튼 우리 집안 사람들이 예전에 그 가문연합이란 곳에 있었단 말이지?","JPN":"つまりうちの家系の人たちが昔、その連合っていうのに所属してたんだよね？","ENG":"So, you’re saying that my family once was in the Family Alliance?","TWN":"總之我們家的人曾經在那個聯盟裡對吧？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네. 비록 나유카 가문이 연합을 떠난 지는 오래되었지만, 오늘 우리가 타인이라 할 만큼은 아닐 것입니다.","JPN":"はい。奈由香家が連合を離れて長い時間が経っておりますが、\\nだからといってお互い他人と言うほどではないでしょう。","ENG":"Yes. The Nayuka family left the Alliance a long time ago, but I dare say that we are not total strangers.","TWN":"對，雖然南裕夏家族已經離開聯盟許久，但如今還是聯盟的人。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그리고 지금, 연합은 나유카 가문의 후손인 나유카 미나토님의 도움이 필요합니다.","JPN":"そして今、連合は奈由香家の子孫である奈由香湊様の助けが必要です。","ENG":"The Alliance now needs your help more than ever, Nayuka Minato, a descendant of the Nayuka family.","TWN":"然後，現在聯盟需要南裕夏家族的後代，也就是你 南裕夏的幫助。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"방금 말했던 위협이란 거, 그게 뭔지도 설명해 줄 수 있어?","JPN":"さっき言ってた脅威っていうのが何なのか、説明してもらえるかな？","ENG":"That threat you mentioned... Could you be more specific?","TWN":"剛說的威脅，能說明一下那是什麼嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……막을 수는 있지만, 지울 수는 없는 것.","JPN":"……阻止はできても、消滅させることはできないもの。","ENG":"It’s something that you can stop, but can’t eliminate.","TWN":"……可以阻止，卻不能清除的東西。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그렇기에 선조들이 오랜 시간 봉인이란 방법을 통해 억눌러왔던 위협입니다.","JPN":"そのため、先祖たちが長きにわたり封印という方法で抑えてきた脅威です。","ENG":"That’s why our ancestors have sealed it away for a long time.","TWN":"所以祖先長久以來都是用封印的方式去克制那個威脅。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저희는 그것을 큰 뱀, <color=#ffd34c>오로치</color>라 부르고 있어요.","JPN":"私たちはそれを大きな蛇、<color=#ffd34c>オロチ</color>と呼んでおります。","ENG":"We call it <color=#ffd34c>Orochi</color>, the Giant Snake.","TWN":"我們稱她為<color=#ffd34c>大蛇</color>。"},"stage":{"bg":"black","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그리고 그 오로치야말로, 이 도시에 퍼지기 시작한 독기의 원흉이랍니다.","JPN":"そしてそのオロチこそ、この都市に広がりつつある毒の元凶です。","ENG":"Orochi is the source of the poison that’s been plaguing this city.","TWN":"而且大蛇才是將毒素散播在這個城市的源頭。"},"stage":{"bg":"black","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"자, 다들 입금 확인하셨죠?","JPN":"さぁ、みんな入金確認はできましたね？","ENG":"Everyone, did you check your account balance?","TWN":"來，大家確認都有收到錢吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"볼일 끝났으면 전 가볼게요.","JPN":"用事が終わったなら秋は帰りますね。","ENG":"Well, I’ll be going if you’re done.","TWN":"沒什麼事的話，那我先走囉。"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"잠깐만, 아직 계좌 여는 중이라고.","JPN":"ちょっと待て、まだ口座を開いているところだ。","ENG":"Wait, I’m still checking my balance.","TWN":"等一下，我還在申請開戶中啦！"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"크윽! 지문인식은 왜 이렇게 안되는 거야?","JPN":"くっ！　なんで指紋認識がうまくいかないんだよ！？","ENG":"Darn! Why can’t you read my fingerprint?","TWN":"呃呃！指紋識別怎麼會這麼差？"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"아, 정확히 수수료만 떼서 넣었으니 걱정 마시라고요.","JPN":"しっかり計算して手数料だけ引いた額を振り込んだから、\\n心配しないでください！","ENG":"I’m telling you, I sent you the exact payment amount, minus my fee.","TWN":"呃，準確地說，就是只有扣掉手續費，請不要擔心。"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"동업한 지 벌써 몇 달이나 됐는데 신용이 없다니까.","JPN":"協働してからもう何ヶ月も経つのに、信用してくれないんですから。","ENG":"We’ve been working together for months, and you still don’t trust me.","TWN":"已經合作多那麼多個月，還這麼疑神疑鬼的。"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"흥, 사람이란 존재를 그렇게 쉽게 믿을 것 같냐. 히로세 아키.","JPN":"ふん、人間という存在をそんな簡単に信じられると思うか、廣瀬秋。","ENG":"Hmpf, I don’t trust people easily, Hirose Aki.","TWN":"哼，你覺得人有那麼可信嗎，廣瀨秋？"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"너넨 프리덤라이더즈 명의로 돈만 받고 있을 뿐이면서, 일을 너무 대충 처리한단 말이야.","JPN":"貴様らはフリーダム・ライダーズ名義で金の受け取りをしてるだけなのに、\\n仕事があまりにも雑すぎる。","ENG":"All you do is receive money in the name of the Freedom Riders—you don’t really take responsibility.","TWN":"你們只是以自由騎士的名義在收錢，辦事卻隨隨便便的。"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그게 불만이면 활동금은 관리국에서 직접 수령하지 그래요?","JPN":"それが不満なら、管理局から直接活動資金を受け取ったらどうですか？","ENG":"If you have a problem with us, you can go ahead and work directly for the Administration.","TWN":"不高興的話，還是你要直接找管理局領活動金？"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그쪽도 라이선스가 없으니 우리 이름 빌려서 토벌보상을 대리 수령하는 거잖아요.","JPN":"そっちもライセンスがないから、秋たちの名義を借りて\\n討伐報酬を代理受領してるわけですよね。","ENG":"But you need us to bring the money for you, because you don’t have a proper license.","TWN":"因爲你們沒有許可證，才借我們的名義代領討伐獎勵不是嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"쳇, 그야 어쩔 수 없잖아. 소속을 대지 않으면 보수도 제대로 챙겨주지 않으니까.","JPN":"チッ、それはしょうがないだろ。\\n所属が無いと報酬もまともに貰えないからな。","ENG":"I can’t help it. The Administration doesn’t pay those who have an uncertain identity.","TWN":"嗟，那也是逼不得已的。因爲沒有所屬的話，根本領不到報酬。"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그러는 너희도 우리 같은 사람들 덕분에 실적 채워서 라이선스 유지하고 있는 거 아냐?","JPN":"そういう貴様らもオレ様みたいな人のおかげで\\n実績を上げてライセンスを維持してるんだろう？","ENG":"Plus, you need people like us to work for you to keep your license.","TWN":"你們不是也託我們的福，才能拿出業績保住許證可不是嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그러니 서로 좋은 게 좋은 거 아니겠어요?","JPN":"だからお互いWinWinでしょう？","ENG":"True. So we’re helping each other.","TWN":"所以對彼此都好不是嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"아무튼 전 집에 갈 거예요. 늦으면 유혹의 함교 본방 놓치거든요.","JPN":"とにかく秋はもう帰ります。\\n早く帰らないと誘惑の艦橋の放送に間に合わなくなります。","ENG":"Anyways, I’m going home. I have to watch The Bridge of Seduction.","TWN":"總之我要回家了。再晚的話會錯過《誘惑的艦橋》首播 。"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"응, 가 봐도 돼.","JPN":"うん、もう大丈夫。","ENG":"Yes, you can go now.","TWN":"嗯，你先走吧。"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"매번 고마워, 아키.","JPN":"いつもありがとう、秋。","ENG":"Thank you, Aki.","TWN":"每次都很謝謝你，廣瀨秋。"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"혹시라도 계산이 안 맞아서 부족하면, 저한테 연락하고요.","JPN":"もし計算が合わなくて足りない時は、秋に連絡してくださいね。","ENG":"If the number doesn’t match, call me.","TWN":"有算錯的話再跟我說吧。"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"엇, 켜졌다!","JPN":"お、繋がった！","ENG":"Finally, it’s on!","TWN":"喔，開好了！"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"하나… 둘….","JPN":"いち……に……","ENG":"One, two...","TWN":"一… 二…"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"하! 내 이럴 줄 알았어.","JPN":"はあ、やっぱりな！","ENG":"Hah! I knew it.","TWN":"哼！我就知道會這樣。"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"수수료 계산을 어떤 식으로 하길래 이번에도 웃돈을 얹어서 입금한 거야?","JPN":"どんな方法で手数料を計算してるんだ？\\n今回も上乗せされた金額が入金されてるぞ？","ENG":"You calculated wrong again! You overpaid me!","TWN":"手續費是怎麼算的，這次是又多算嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"매번 번거롭게 돌려 주는 쪽 입장도 생각하라고!","JPN":"毎回手間をかけて返す側の立場も考えろよな！","ENG":"It’s such a hassle to return the extra money, you know?","TWN":"每次都還要還她，很麻煩欸！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"뭐야? 벌써 갔나?","JPN":"なんだ？　もう帰ったのか？","ENG":"Huh? She’s gone already?","TWN":"搞什麼？這麼快就走啦？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"하하… 다음 번에 얘기하면 되니까 신경 쓰지 마.","JPN":"あはは……今度話せばいいんじゃない？","ENG":"Don’t worry about it. We can tell her next time.","TWN":"哈哈… 下次再說吧，不用太在意。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그나저나 별일이네. 네가 그렇게 열을 올리기도 하고.","JPN":"というか珍しいな。お前がそこまで熱くなるなんて。","ENG":"By the way, I’ve never seen you so serious.","TWN":"這又不是什麼大事，你幹嘛發那麼大脾氣。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"정말 괜찮겠냐, 미나토?","JPN":"本当に大丈夫か、湊？","ENG":"Are you alright, Minato?","TWN":"真的沒關係嗎，南裕夏？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"응? 뭐가?","JPN":"え？　なにが？","ENG":"About what?","TWN":"嗯？什麼？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"어제 일.","JPN":"昨日のことだ。","ENG":"About what happened yesterday.","TWN":"昨天的事情。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"널 찾아온 나나하라 사람 말이야. 돕는 걸 생각해 보겠다고 했잖아.","JPN":"昨日来た七原の子のことだよ。\\n力を貸すかどうか考えてみるって返事しただろ。","ENG":"That Nanahara girl. You told her you’d think about helping them.","TWN":"那個叫七原的人不是來找你嗎？你不是說會考慮嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"응. 그 애가 직접 날 만나러 왔다고 하는데 딱 잘라서 거절하긴 좀 그렇잖아.","JPN":"うん。あの子がわざわざ僕に会いにきたのに、\\nきっぱり断るのはちょっとあれだし。","ENG":"Well, she came a long way to see me. I couldn’t just say no to her face.","TWN":"嗯，她親自來找我，就這樣拒絕人家好像有點不好意思。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"정식 태스크포스 명함을 확인하기도 했고.","JPN":"正式なタスクフォースカンパニーの名刺も見せてもらったしな。","ENG":"She also had a real TASKFORCE business card.","TWN":"而且我還確認人家特遣勢力的名片。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"우유부단한 녀석 같으니라고…….","JPN":"優柔不断なやつだな……","ENG":"You’re so soft, man.","TWN":"真是個優柔寡斷的傢伙……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그런 식으로 무턱대고 받아들이면 후회할 거다.","JPN":"そうやって良かれと思って簡単に承諾したら、後で後悔するぞ。","ENG":"You’ll regret it if you accept every offer that’s laid before you.","TWN":"就那樣隨便答應的話你會後悔的。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"지금까지 카운터인 걸 다른 녀석들한테 숨긴 것도 조용히 학교를 다니고 싶어서였잖아.","JPN":"今までカウンターであることを他のやつらに隠してたのも、\\n目立たず静かに学校生活を送りたかったからだろ。","ENG":"You didn’t tell others that you’re a Counter because you wanted to have an ordinary school life.","TWN":"你之所以一直瞞著大家你是制裁者的事，不就是因為想要低調上學嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"……그러게. 이런 일에 휘말리지 않으려고 계속 노력했는데 말이지.","JPN":"……そうだな。こんなことに巻き込まれないようにずっと努力してきたのにな。","ENG":"... That’s true. I’ve been trying to avoid something like this.","TWN":"……是沒錯，我一直很努力地要避開這種事。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"어째서인지 그땐 마음이 조금 흔들렸어.","JPN":"なぜかあの時は心が少し揺れてしまったんだ。","ENG":"But for some reason, I couldn’t say no to her.","TWN":"可是不知爲什麼，那時候心有點動搖。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그 여자애.","JPN":"あの子……","ENG":"That girl.","TWN":"那個女生，"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"내 도움이 필요하다고 말하는데…… 평범한 스카우트 제의 같진 않았거든.","JPN":"僕の助けが必要だと言った時……ただのスカウトのようには思えなくて。","ENG":"She said she needed my help... and it didn’t sound like an ordinary scout offer.","TWN":"說需要我的幫忙……總覺得跟一般遊說的感覺不太一樣。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"카운터가 된 이상, 결국 이렇게 될 운명이 아니었을까…… 하는 생각이 들 정도로.","JPN":"カウンターになった以上、結局こうなる運命だったのかな……って思うぐらいにはね。","ENG":"It almost felt like... meant to be. The reason I became a Counter.","TWN":"我內心甚至出現這種想法，既然身為制裁者，這或許就是制裁者的命運吧……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"농담하는 거 아냐, 미나토. 함부로 그 애랑 얽혔다간 죽을 수도 있다고.","JPN":"冗談じゃねえぞ、湊。下手にあの子と絡んだら、死ぬことだってあり得る。","ENG":"I’m not kidding, Minato. You might get yourself killed if you hang around with her.","TWN":"我沒在跟你開玩笑，南裕夏。隨便跟那種人扯上關係，很可能會喪命的。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"하긴, 그런 옷차림으로 다니는 태스크포스라면 평범이랑은 거리가 멀긴 해.","JPN":"確かに、あんな格好しているタスクフォースカンパニーなら平凡とはかけ離れてるよね。","ENG":"Yeah, a TASKFORCE with a dress code like that is not common, I guess.","TWN":"也是，雖然是特遣勢力，但看她的穿著就不太平凡。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그래도 우리 침식체랑 꽤 많이 싸워 봤잖아. 평소에 하던 대로 하면 되겠지.","JPN":"でも、僕たちだって侵食体と結構戦ってきただろ。いつもどおりにすればいいと思うんだ。","ENG":"But we’ve fought quite a lot of C.O.s so far. I’ll be okay.","TWN":"可是我們不是經常和侵蝕體戰鬥嗎？應該就跟平時差不多吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그래. 정 그렇다면 마음대로 해라.","JPN":"そうか。なら勝手にしろ。","ENG":"Okay, then. Suit yourself.","TWN":"好吧，那就隨便你吧。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"……마사키? 어디 가는 거야?","JPN":"……雅紀？　どこに行くんだ？","ENG":"Masaki? Where are you going?","TWN":"……雅紀？你要去哪裡？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"저 녀석…… 혹시 화난 건가?","JPN":"あいつ……もしかして怒ってるのか？","ENG":"Is he... angry?","TWN":"那傢伙……是在生氣嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아, 네. 나유카입니다. 선생님. 무슨 일이세요?","JPN":"はい、奈由香です。先生、どうしたんですか？","ENG":"This is Nayuka speaking. Hello, teacher. Why did you call me?","TWN":"喂，是，我是南裕夏。老師有什麼事情嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TEACHER_NPC_ARCHERY_NULL","text":{"KOREA":"미나토, 네가 이로하를 어제 응급실로 데려갔다던데…….","JPN":"湊、昨日君がいろはを病院に連れていったと聞いたが……","ENG":"Minato, I heard you brought Iroha to the ER yesterday.","TWN":"南裕夏，聽說你昨天送伊呂波去急診……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L20_1","type":"dialog","speaker":"TEACHER_NPC_ARCHERY_NULL","text":{"KOREA":"두 사람. 어제 같이 학교를 빠져나갔던 거니?","JPN":"昨日二人で学校を抜け出したのか？","ENG":"Did you two leave the school during the Corruption alert?","TWN":"你們昨天是一起翹課嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"Um...","TWN":"那是……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"죄송해요, 선생님.","JPN":"ごめんなさい、先生。","ENG":"I’m sorry, teacher.","TWN":"老師對不起。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TEACHER_NPC_ARCHERY_NULL","text":{"KOREA":"미나토.","JPN":"湊。","ENG":"Minato.","TWN":"南裕夏。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TEACHER_NPC_ARCHERY_NULL","text":{"KOREA":"지금부터 병원에 가보려고 하는데, 너도 같이 가겠니?","JPN":"今から病院に行こうと思うんだが、君も一緒に行くか？","ENG":"I’m going to the hospital now. Would you like to come with me?","TWN":"我現在要去一趟醫院，你要一起去嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"……네?","JPN":"……はい？","ENG":"Huh?","TWN":"……嗯？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};